// // Asynchronous reset sets Q to 0 and QN to 1, while asynchronous set sets Q to 1 and QN to 0
module top_module(T, S, R, CLK, Q, QN);input T, S, R, CLK;
  output Q, QN;
  reg Q, QN;

  always @(posedge CLK) begin
    if (S) begin
      Q <= 1;
      QN <= 0;
    end else if (R) begin
      Q <= 0;
      QN <= 1;
    end else if (T) begin
      Q <= ~Q;
      QN <= ~QN;
    end
  end
endmodule
